      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "additionalProperties": false,
        "required": [
          "record_type",
          "record_id",
          "path",
          "change_type",
          "rationale"
        ],
        "properties": {
          "record_type": {
            "type": "string"
          },
          "record_id": {
            "$ref": "./common.schema.json#/$defs/identifier"
